import type { SupabaseClient } from "@supabase/supabase-js";
import {
  GLOBAL_EVENT_PRIORITY,
  GLOBAL_EVENTS,
  type GlobalEventDefinition,
  type GlobalEventId,
} from "../data/globalEvents";

export type ResolvedGlobalLiveEvent = {
  id: GlobalEventId;
  headlineShort: string;
  tagline: string;
  pulseLine: string;
  xpMultiplier: number;
  factionPointsMultiplier: number;
  /** Epoch ms UTC — Fensterende am selben UTC-Kalendertag wie serverMs */
  endsAtMs: number;
};

function utcMinutesSinceMidnight(serverMs: number): number {
  const d = new Date(serverMs);
  return d.getUTCHours() * 60 + d.getUTCMinutes() + d.getUTCSeconds() / 60 + d.getUTCMilliseconds() / 60000;
}

function windowEndEpochMs(serverMs: number, w: GlobalEventDefinition["window"]): number {
  const d = new Date(serverMs);
  const y = d.getUTCFullYear();
  const mo = d.getUTCMonth();
  const da = d.getUTCDate();
  const eh = Math.floor(w.endMinuteUtc / 60);
  const em = w.endMinuteUtc % 60;
  return Date.UTC(y, mo, da, eh, em, 0, 0);
}

function isInsideWindow(serverMs: number, w: GlobalEventDefinition["window"]): boolean {
  const m = utcMinutesSinceMidnight(serverMs);
  return m >= w.startMinuteUtc && m < w.endMinuteUtc;
}

export function resolveActiveGlobalLiveEvent(serverMs: number): ResolvedGlobalLiveEvent | null {
  for (const id of GLOBAL_EVENT_PRIORITY) {
    const def = GLOBAL_EVENTS[id];
    if (!isInsideWindow(serverMs, def.window)) continue;
    return {
      id: def.id,
      headlineShort: def.headlineShort,
      tagline: def.tagline,
      pulseLine: def.pulseLine,
      xpMultiplier: def.xpMultiplier,
      factionPointsMultiplier: def.factionPointsMultiplier,
      endsAtMs: windowEndEpochMs(serverMs, def.window),
    };
  }
  return null;
}

/** Supabase-RPC — autoritative UTC-Epoch-ms */
export async function fetchCodesnapServerNowMs(sb: SupabaseClient): Promise<number | null> {
  const { data, error } = await sb.rpc("codesnap_server_epoch_ms_utc");
  if (error || data == null) return null;
  const n = typeof data === "number" ? data : typeof data === "string" ? Number(data) : Number(data);
  return Number.isFinite(n) ? Math.floor(n) : null;
}
